"""
Basic tests for the integrate API endpoints.

Uses SimpleTestCase with mocked viewset methods so no database connection
is required — tests run in any environment without Docker.
"""

from django.http import Http404
from django.test import SimpleTestCase
from unittest.mock import patch, MagicMock
from integrate.models import Disciplina, Tema, Jogo, Livro, Exercicio, Aula
from integrate.views import (
    DisciplinaViewSet,
    TemaViewSet,
    JogoViewSet,
    LivroViewSet,
    ExercicioViewSet,
    AulaViewSet,
)

# Fake model instances (unsaved — UUIDs auto-generated by field default


def _disciplina(**kw):
    """Build an unsaved Disciplina instance."""
    return Disciplina(
        nome=kw.get("nome", "Matemática"),
        slug=kw.get("slug", "matematica"),
        desc=kw.get("desc", "Descrição"),
    )


def _tema(**kw):
    """Build an unsaved Tema instance with a linked Disciplina."""
    d = _disciplina()
    return Tema(
        titulo=kw.get("titulo", "Adição"),
        slug=kw.get("slug", "adicao"),
        desc=kw.get("desc", "Descrição"),
        ano_escolar=kw.get("ano_escolar", "1º Ano"),
        seccao=kw.get("seccao", "aprender"),
        disciplina=d,
    )


def _jogo(**kw):
    """Build an unsaved Jogo instance."""
    return Jogo(
        titulo=kw.get("titulo", "Jogo A"),
        descricao=kw.get("descricao", "Desc"),
        publicado=kw.get("publicado", True),
    )


def _livro(**kw):
    """Build an unsaved Livro instance."""
    return Livro(
        titulo=kw.get("titulo", "Livro A"),
        autor=kw.get("autor", "Autor"),
        faixa_etaria=kw.get("faixa_etaria", "6-8"),
        resumo=kw.get("resumo", "Resumo"),
        publicado=kw.get("publicado", True),
    )


def _exercicio(**kw):
    """Build an unsaved Exercicio instance."""
    return Exercicio(
        title=kw.get("title", "Ex 1"),
        level=kw.get("level", 1),
        subject_id=kw.get("subject_id", "matematica"),
        publicado=kw.get("publicado", True),
    )


def _aula(**kw):
    """Build an unsaved Aula instance."""
    return Aula(
        title=kw.get("title", "Aula 1"),
        subject_id=kw.get("subject_id", "matematica"),
        level=kw.get("level", 1),
        publicado=kw.get("publicado", True),
    )


# Disciplin


class DisciplinaListTest(SimpleTestCase):
    """Tests for GET /api/disciplinas/."""

    @patch.object(DisciplinaViewSet, "get_queryset")
    def test_returns_200(self, mock_gqs):
        """List endpoint is publicly accessible and returns HTTP 200."""
        mock_gqs.return_value = [_disciplina()]
        response = self.client.get("/api/disciplinas/")
        self.assertEqual(response.status_code, 200)

    @patch.object(DisciplinaViewSet, "get_queryset")
    def test_returns_all_disciplines(self, mock_gqs):
        """Response body contains every discipline returned by the queryset."""
        mock_gqs.return_value = [
            _disciplina(nome="Matemática", slug="matematica"),
            _disciplina(nome="Português", slug="portugues"),
        ]
        response = self.client.get("/api/disciplinas/")
        self.assertEqual(len(response.json()), 2)

    @patch.object(DisciplinaViewSet, "get_object")
    def test_detail_returns_200(self, mock_get_obj):
        """Detail endpoint returns HTTP 200 when the object exists."""
        mock_get_obj.return_value = _disciplina()
        response = self.client.get("/api/disciplinas/matematica/")
        self.assertEqual(response.status_code, 200)

    @patch.object(DisciplinaViewSet, "get_object")
    def test_detail_unknown_slug_returns_404(self, mock_get_obj):
        """Detail with a slug that doesn't exist returns HTTP 404."""
        mock_get_obj.side_effect = Http404
        response = self.client.get("/api/disciplinas/nao-existe/")
        self.assertEqual(response.status_code, 404)


