# Auth — Logi


class LoginTest(SimpleTestCase):
    """Tests for POST /api/v1/login."""

    @patch("integrate.auth_views.RefreshToken")
    @patch("integrate.auth_views.authenticate")
    def test_valid_credentials_return_200(self, mock_auth, MockToken):
        """Correct username/password returns HTTP 200 and a success detail message."""
        mock_auth.return_value = MagicMock()
        response = self.client.post(
            "/api/v1/login",
            data={"username": "prof", "password": "pass1234"},
            content_type="application/json",
        )
        self.assertEqual(response.status_code, 200)
        self.assertIn("detail", response.json())

    @patch("integrate.auth_views.authenticate", return_value=None)
    def test_invalid_credentials_return_401(self, _mock_auth):
        """Wrong password returns HTTP 401."""
        response = self.client.post(
            "/api/v1/login",
            data={"username": "prof", "password": "errada"},
            content_type="application/json",
        )
        self.assertEqual(response.status_code, 401)

    @patch("integrate.auth_views.RefreshToken")
    @patch("integrate.auth_views.authenticate")
    def test_sets_access_cookie_on_success(self, mock_auth, MockToken):
        """A successful login sets the access_token cookie."""
        mock_auth.return_value = MagicMock()
        response = self.client.post(
            "/api/v1/login",
            data={"username": "prof", "password": "pass1234"},
            content_type="application/json",
        )
        self.assertIn("access_token", response.cookies)


